// ============ RANKING TABLE ============
function initRankingTable() {
  function render() {
    const list = document.getElementById('rankingList');
    if (!list) return;
    list.innerHTML = RANKINGS.map((r, i) => `
      <div class="rank-item pos-${i+1}">
        <div class="rank-pos">${String(i+1).padStart(2,'0')}</div>
        <div class="rank-flag">${r.flag}</div>
        <div class="rank-name">${r.name.toUpperCase()}</div>
        <div class="rank-score">${r.score}</div>
        <div class="rank-trend ${r.cls}">${r.cls === 'trend-up' ? '↑' : r.cls === 'trend-down' ? '↓' : '–'} ${r.trend}</div>
      </div>
    `).join('');
  }
  render();
  // Simulate live updates
  setInterval(() => {
    RANKINGS.forEach(r => {
      const cur = parseInt(r.score.replace(' ', ''));
      const delta = Math.floor(Math.random() * 40) - 10;
      const newVal = Math.max(0, cur + delta);
      r.score = newVal.toLocaleString('fr-FR');
    });
    render();
  }, 1800);
}

// ============ MAP TOOLTIPS — REAL MAP ============
function initMapTooltips() {
  var tooltip = document.getElementById("mapTooltip");
  var container = document.getElementById("realMapContainer");
  if (!tooltip || !container) return;

  var statsMap = {
    france:          { pop:"9 847", trend:"+12%", cmd:"3 241" },
    bresil:          { pop:"8 521", trend:"+9%",  cmd:"2 847" },
    argentine:       { pop:"7 633", trend:"-1%",  cmd:"2 544" },
    maroc:           { pop:"6 249", trend:"+18%", cmd:"2 083" },
    etats_unis:      { pop:"5 880", trend:"+7%",  cmd:"1 960" },
    algerie:         { pop:"5 112", trend:"+15%", cmd:"1 704" },
    espagne:         { pop:"4 756", trend:"+3%",  cmd:"1 585" },
    portugal:        { pop:"4 301", trend:"+5%",  cmd:"1 434" },
    canada:          { pop:"3 210", trend:"+4%",  cmd:"1 070" },
    allemagne:       { pop:"4 120", trend:"+6%",  cmd:"1 373" },
    angleterre:      { pop:"3 980", trend:"+8%",  cmd:"1 327" },
    senegal:         { pop:"2 890", trend:"+11%", cmd:"963" },
    japon:           { pop:"3 100", trend:"+9%",  cmd:"1 033" },
    coree_sud:       { pop:"2 760", trend:"+7%",  cmd:"920" },
    arabie_saoudite: { pop:"1 980", trend:"+5%",  cmd:"660" },
    australie:       { pop:"1 650", trend:"+4%",  cmd:"550" },
  };

  document.querySelectorAll(".hs-group").forEach(function(el) {
    el.addEventListener("mouseenter", function(e) {
      var country = el.getAttribute("data-country");
      var name    = el.getAttribute("data-name") || country;
      var flag    = el.getAttribute("data-flag") || "";
      var rank    = el.getAttribute("data-rank");
      var s = statsMap[country] || { pop:"1 200", trend:"+5%", cmd:"400" };
      var trendColor = s.trend.charAt(0) === "+" ? "#4CAF50" : "#F44336";
      var rankHtml = rank ? `<div style='font-size:12px;color:#C9A84C;margin-bottom:6px'>RANG #${rank}</div>` : '';
      tooltip.className = "map-tooltip visible";
      tooltip.innerHTML = `<div class='tooltip-country'>${flag} ${name}</div>${rankHtml}<div class='tooltip-stat'><span>Commandes</span><span>${s.cmd}</span></div><div class='tooltip-stat'><span>Score</span><span>${s.pop}</span></div><div class='tooltip-trend' style='color:${trendColor}'>Tendance ${s.trend} ce mois</div>`;
      var rect = container.getBoundingClientRect();
      var tx = e.clientX - rect.left + 14;
      var ty = e.clientY - rect.top + 14;
      if (tx + 220 > rect.width)  tx = e.clientX - rect.left - 230;
      if (ty + 120 > rect.height) ty = e.clientY - rect.top - 130;
      tooltip.style.left = tx + "px";
      tooltip.style.top  = ty + "px";
    });
    el.addEventListener("mouseleave", function() { tooltip.className = "map-tooltip"; });
    el.addEventListener("click", function() {
      var country = el.getAttribute("data-country");
      var found = COUNTRIES.find(function(c) { return c.id === country; });
      if (found) openCountryModal(found);
    });
  });
}

