function closeModal() {
  document.getElementById('country-modal').classList.remove('open');
  document.getElementById('modal-overlay').classList.remove('visible');
  document.body.style.overflow = '';
}

function selectSize(e, type, size) {
  e.stopPropagation();
  document.querySelectorAll(`#sz-${type} .size-btn`).forEach(b => b.classList.remove('active'));
  e.target.classList.add('active');
  selectedSizes[type] = size;
}

function addToCartFromModal(id, name, file, price) {
  addToCart({ id, name, image: imgMaillot(file), price, size:'M' });
  closeModal();
}

// ============ CART ============
function addToCart(item) {
  const ex = cart.find(c => c.id === item.id && c.size === item.size);
  ex ? ex.qty++ : cart.push({ ...item, qty:1 });
  saveCart(); updateCartUI(); openCartBriefly(); flashAdded();
}

function quickAdd(e, id, name, file, price) {
  e.stopPropagation();
  addToCart({ id, name, image: imgMaillot(file), price, size:'M' });
}

function addSignedToCart(name, country, imgKey, price) {
  addToCart({ id:'signed-'+name.toLowerCase().replace(/\s+/g,'-'), name:'Maillot signé '+name, image: getImg(imgKey), price, size:'Unique' });
}

function removeFromCart(i) {
  cart.splice(i, 1); saveCart(); updateCartUI();
}

function saveCart() { try { localStorage.setItem('wk2026_v2', JSON.stringify(cart)); } catch(e){} }
function loadCart() { try { const s = localStorage.getItem('wk2026_v2'); if(s) cart = JSON.parse(s); updateCartUI(); } catch(e){} }

function updateCartUI() {
  const total = cart.reduce((s,c) => s + c.price * c.qty, 0);
  const count = cart.reduce((s,c) => s + c.qty, 0);
  document.getElementById("cart-count").textContent = count;
  document.getElementById("cart-count-badge").textContent = count;
  document.getElementById("cart-total-price").textContent = fp(total);
  const el = document.getElementById("cart-items");
  if (count === 0) {
    el.innerHTML = `<div style="text-align:center;padding:44px 0;color:var(--text-muted);font-family:'Barlow Condensed',sans-serif;letter-spacing:1px;font-size:14px">Votre sélection est vide</div>`;
  } else {
    el.innerHTML = cart.map((item, i) => `
      <div class="cart-item">
        <img src="${item.image}" alt="${item.name}">
        <div class="cart-item-info">
          <div class="cart-item-name">${item.name}</div>
          <div class="cart-item-size">Taille : ${item.size} · Qté : ${item.qty}</div>
        </div>
        <div class="cart-item-price">${fp(item.price)}</div>
        <button class="cart-item-remove" onclick="removeFromCart(${i})">✕</button>
      </div>
    `).join("");
  }
}
function toggleCart() {
  const s = document.getElementById('cart-sidebar');
  const o = document.getElementById('cart-overlay');
  const open = s.classList.toggle('open');
  o.classList.toggle('visible', open);
  document.body.style.overflow = open ? 'hidden' : '';
}

