// ============ PROMO BUTTON ============
function initPromoBtn() {
  const btn = document.getElementById('promoBtn');
  const used = checkPromoUsed();
  if (used) {
    btn.classList.add('used');
    btn.querySelector(".promo-btn-text").textContent = "OFFRE UTILISÉE AUJOURD'HUI";
  }
  // Countdown to midnight
  function updatePromoCountdown() {
    const now = new Date();
    const midnight = new Date(now);
    midnight.setHours(24,0,0,0);
    const diff = midnight - now;
    const h = Math.floor(diff / 3600000);
    const m = Math.floor((diff % 3600000) / 60000);
    const s = Math.floor((diff % 60000) / 1000);
    const el = document.getElementById('promoCountdown');
    if(el) el.textContent = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
  }
  updatePromoCountdown();
  setInterval(updatePromoCountdown, 1000);
}

function checkPromoUsed() {
  try {
    const stored = localStorage.getItem('wk2026_promo_date');
    if (!stored) return false;
    return stored === new Date().toDateString();
  } catch(e) { return false; }
}

function markPromoUsed() {
  try { localStorage.setItem('wk2026_promo_date', new Date().toDateString()); } catch(e){}
}

function triggerPromo() {
  const btn = document.getElementById('promoBtn');
  if (btn.classList.contains('used')) {
    showBonusUsed(); return;
  }
  markPromoUsed();
  btn.classList.add('used');
  // Flash effect
  let flashes = 0;
  const fi = setInterval(() => {
    document.body.style.background = flashes%2===0 ? 'rgba(200,25,42,0.08)' : 'var(--blue-deep)';
    flashes++; if(flashes > 6) { clearInterval(fi); document.body.style.background = ''; }
  }, 90);
  launchConfetti();
  setTimeout(showBonusModal, 700);
}

const GIFTS = [
  { reward:'UN MAILLOT OFFERT', msg:'Commandez 1 maillot, recevez-en 2. Le second sera glissé dans votre colis sans figurer sur la facture — c\'est un cadeau de notre part.', imgKey:'maillot_france' },
  { reward:'ACCESSOIRE SUPPORTER OFFERT', msg:'Une écharpe supporter officielle est ajoutée à votre prochain colis. Valeur 25 €. Aucun code requis — c\'est automatique.', imgKey:'maillot_bresil' },
  { reward:'2ÈME ARTICLE À −50%', msg:'Votre second maillot bénéficie d\'une réduction additionnelle de 50%. Applicable automatiquement au moment du paiement.', imgKey:'maillot_argentine' },
];

function showBonusModal() {
  const gift = GIFTS[Math.floor(Math.random() * GIFTS.length)];
  const modal = document.getElementById("bonus-modal");
  const content = document.getElementById("bonus-content");
  content.innerHTML = `
    <span class="bonus-icon">🎯</span>
    <div class="bonus-title">BONUS DÉBLOQUÉ</div>
    <p style="color:var(--text-muted);font-size:13px;margin-bottom:14px;font-family:'Barlow Condensed',sans-serif;letter-spacing:1px">Votre offre exclusive du jour est activée</p>
    <div class="bonus-reward">${gift.reward}</div>
    <div class="bonus-img-wrap"><img src="${getImg(gift.imgKey)}" alt="Cadeau"></div>
    <div class="bonus-message">${gift.msg}</div>
    <button class="btn-primary" onclick="closeBonus();openCartBriefly()" style="width:100%;padding:14px">Commander maintenant</button>
    <div class="bonus-tomorrow">Revenez demain pour une nouvelle chance</div>
  `;
  modal.classList.add("open");
}
function showBonusUsed() {
  const modal = document.getElementById("bonus-modal");
  const content = document.getElementById("bonus-content");
  content.innerHTML = `
    <span class="bonus-icon">🕐</span>
    <div class="bonus-title" style="color:var(--text-muted)">OFFRE UTILISÉE</div>
    <p style="color:var(--text-muted);margin:16px 0 24px;line-height:1.6">Vous avez déjà utilisé votre bonus du jour.<br>Revenez demain pour une nouvelle offre exclusive.</p>
    <div style="font-family:'Bebas Neue',sans-serif;font-size:22px;color:#FF6B6B;margin-bottom:20px">Prochain bonus dans : <span id="modalCountdown">--:--:--</span></div>
    <button class="btn-primary" onclick="closeBonus()" style="width:100%;padding:14px">Fermer</button>
  `;
  modal.classList.add("open");
  function tick() {
    const now = new Date(); const mid = new Date(now); mid.setHours(24,0,0,0);
    const d = mid - now;
    const h = String(Math.floor(d/3600000)).padStart(2,"0");
    const m = String(Math.floor((d%3600000)/60000)).padStart(2,"0");
    const s = String(Math.floor((d%60000)/1000)).padStart(2,"0");
    const el = document.getElementById("modalCountdown");
    if(el) el.textContent = h + ":" + m + ":" + s;
  }
  tick();
  const ti = setInterval(() => { if(!document.getElementById("modalCountdown")) clearInterval(ti); else tick(); }, 1000);
}
function closeBonus() { document.getElementById('bonus-modal').classList.remove('open'); }


